-- Anti-Debugging & Hooking Protection Tier 1
-- Memblokir fungsi-fungsi yang biasa digunakan exploiter untuk mendump string memori
if (debug and debug.getinfo) then
    local _check = tostring(debug.getinfo(print))
    if not _check:find("built%-in") then 
        while true do end -- Crash executor jika print di-hook oleh Logger
    end
end

-- Virtual Bitwise Logic Decryptor
local _bit = bit or bit32 or (bitwise and bitwise.bxor)
local function _VM_DECRYPT(a, b)
    if _bit and _bit.bxor then
        return _bit.bxor(a, b)
    else
        local p, r = 1, 0
        while a > 0 or b > 0 do
            local ra, rb = a % 2, b % 2
            if ra ~= rb then r = r + p end
            a, b, p = (a - ra) / 2, (b - rb) / 2, p * 2
        end
        return r
    end
end

-- Virtual Program Counter (PC) & Memory Allocation Execution Loop
for _PC = 1, #_VM_STREAM do
    local _OPCODE = _VM_STREAM[_PC]
    -- Memulihkan instruksi biner asli langsung di memori RAM terisolasi
    _MEM_BUFFER[_PC] = string.char(_VM_DECRYPT(_OPCODE, _VM_KEY))
end

-- Eksekusi aman melalui JIT internal executor tanpa menulis file fisik (.lua)
local _RUN_VM = loadstring or load
local _VIRTUAL_ENV, _ERR = _RUN_VM(table.concat(_MEM_BUFFER))

if _VIRTUAL_ENV then
    -- Bersihkan memory buffer setelah eksekusi selesai agar tidak bisa didump dari RAM
    _MEM_BUFFER = nil
    _VM_STREAM = nil
    
    _VIRTUAL_ENV(...)
else
    error("Fatal: Virtual Machine Memory Tampered. Code execution blocked.")
end
